"use client"

import { createContext, useContext } from "react"
import {
  useThemeToken,
  type UseThemeTokenOptions,
  type UseThemeTokenReturn,
} from "./use-theme-token"
import {
  ThemeTokenSettingsUi,
  type ThemeTokenSettingsUiProps,
} from "./theme-token-settings-ui"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { useThemeToken } from "./use-theme-token"
export type {
  UseThemeTokenOptions,
  UseThemeTokenReturn,
  ThemeTokenStatus,
} from "./use-theme-token"
export { ThemeTokenSettingsUi } from "./theme-token-settings-ui"
export type { ThemeTokenSettingsUiProps } from "./theme-token-settings-ui"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

const ThemeTokenContext = createContext<UseThemeTokenReturn | null>(null)

/**
 * Access the ThemeToken context provided by `ThemeTokenProvider`.
 *
 * @throws If called outside of a `ThemeTokenProvider`.
 *
 * @example
 * ```tsx
 * const { origin, setOrigin, clearOrigin, isLoading } = useThemeTokenContext()
 * ```
 */
export function useThemeTokenContext(): UseThemeTokenReturn {
  const ctx = useContext(ThemeTokenContext)
  if (!ctx) {
    throw new Error(
      "useThemeTokenContext must be used within a <ThemeTokenProvider>",
    )
  }
  return ctx
}

// ---------------------------------------------------------------------------
// Provider
// ---------------------------------------------------------------------------

/** Props for the ThemeTokenProvider component */
export interface ThemeTokenProviderProps extends UseThemeTokenOptions {
  /** Child elements to wrap */
  children?: React.ReactNode
  /** Additional CSS classes on the wrapper div */
  className?: string
}

/**
 * Provides on-chain theme state to the component tree.
 *
 * On mount, reads the saved origin from localStorage (or uses `defaultOrigin`),
 * fetches the ThemeToken from the blockchain, and applies its CSS variables to
 * the document root. All children can access the theme state via
 * `useThemeTokenContext()`.
 *
 * @example
 * ```tsx
 * <ThemeTokenProvider defaultOrigin="abc123_0">
 *   <App />
 * </ThemeTokenProvider>
 * ```
 */
export function ThemeTokenProvider({
  children,
  className,
  defaultOrigin,
  storageKey,
  onThemeApplied,
  onThemeCleared,
  onError,
}: ThemeTokenProviderProps) {
  const themeToken = useThemeToken({
    defaultOrigin,
    storageKey,
    onThemeApplied,
    onThemeCleared,
    onError,
  })

  return (
    <ThemeTokenContext.Provider value={themeToken}>
      <div className={className}>{children}</div>
    </ThemeTokenContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// Settings (composed)
// ---------------------------------------------------------------------------

/** Props for the composed ThemeTokenSettings component */
export interface ThemeTokenSettingsProps {
  /** Callback fired after a theme is applied */
  onApply?: (origin: string) => void
  /** Callback fired when the theme is cleared */
  onClear?: () => void
  /** Additional CSS classes */
  className?: string
}

/**
 * Settings panel that reads from `ThemeTokenProvider` context.
 *
 * Must be rendered inside a `<ThemeTokenProvider>`. Wires the
 * `ThemeTokenSettingsUi` to the context's state and actions.
 *
 * @example
 * ```tsx
 * <ThemeTokenProvider>
 *   <ThemeTokenSettings />
 * </ThemeTokenProvider>
 * ```
 */
export function ThemeTokenSettings({
  onApply,
  onClear,
  className,
}: ThemeTokenSettingsProps) {
  const { origin, theme, status, error, setOrigin, clearOrigin } =
    useThemeTokenContext()

  const handleApply = async (newOrigin: string) => {
    await setOrigin(newOrigin)
    onApply?.(newOrigin)
  }

  const handleClear = () => {
    clearOrigin()
    onClear?.()
  }

  return (
    <ThemeTokenSettingsUi
      origin={origin}
      themeName={theme?.name ?? null}
      status={status}
      errorMessage={error?.message ?? null}
      onApply={handleApply}
      onClear={handleClear}
      className={className}
    />
  )
}

"use client"

import { useCallback, useState } from "react"
import { Loader2, Palette, RotateCcw, Check, AlertCircle } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { cn } from "@/lib/utils"
import type { ThemeTokenStatus } from "./use-theme-token"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Color swatch entry for the preview grid */
interface ColorSwatch {
  /** Display label */
  label: string
  /** CSS variable name (e.g. "primary") */
  variable: string
}

/** Props for the settings panel UI */
export interface ThemeTokenSettingsUiProps {
  /** Currently active theme origin, or null */
  origin: string | null
  /** Theme name from the fetched ThemeToken */
  themeName: string | null
  /** Current lifecycle status */
  status: ThemeTokenStatus
  /** Error message if status is "error" */
  errorMessage: string | null
  /** Callback to apply a theme by origin */
  onApply: (origin: string) => void
  /** Callback to clear the active theme */
  onClear: () => void
  /** Additional CSS classes */
  className?: string
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const COLOR_SWATCHES: ColorSwatch[] = [
  { label: "Primary", variable: "primary" },
  { label: "Secondary", variable: "secondary" },
  { label: "Accent", variable: "accent" },
  { label: "Muted", variable: "muted" },
  { label: "Destructive", variable: "destructive" },
  { label: "Background", variable: "background" },
  { label: "Card", variable: "card" },
  { label: "Border", variable: "border" },
]

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

/**
 * Settings panel for selecting and applying on-chain themes.
 *
 * Displays an origin input, apply/reset buttons, the current theme status,
 * and a preview grid of the active color swatches read from CSS variables.
 */
export function ThemeTokenSettingsUi({
  origin,
  themeName,
  status,
  errorMessage,
  onApply,
  onClear,
  className,
}: ThemeTokenSettingsUiProps) {
  const [inputValue, setInputValue] = useState(origin ?? "")

  const handleApply = useCallback(() => {
    const trimmed = inputValue.trim()
    if (trimmed.length === 0) return
    onApply(trimmed)
  }, [inputValue, onApply])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === "Enter") {
        handleApply()
      }
    },
    [handleApply],
  )

  const isLoading = status === "loading"
  const isApplied = status === "applied"
  const isError = status === "error"

  return (
    <Card className={cn("w-full max-w-md", className)}>
      <CardHeader>
        <div className="flex items-center gap-2">
          <Palette className="size-5 text-muted-foreground" aria-hidden="true" />
          <CardTitle>Theme Token</CardTitle>
        </div>
        <CardDescription>
          Apply an on-chain theme by entering its origin (txid_vout format).
        </CardDescription>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* Origin input */}
        <div className="flex flex-col gap-2">
          <Label htmlFor="theme-origin">Origin</Label>
          <Input
            id="theme-origin"
            placeholder="e.g. abc123def456…_0"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={handleKeyDown}
            disabled={isLoading}
            aria-describedby="theme-origin-hint"
          />
          <p id="theme-origin-hint" className="text-xs text-muted-foreground">
            The origin outpoint of an inscribed ThemeToken.
          </p>
        </div>

        {/* Status badge */}
        {status !== "idle" && (
          <div className="flex items-center gap-2">
            {isLoading && (
              <Badge variant="secondary" className="gap-1.5">
                <Loader2
                  className="size-3 animate-spin"
                  aria-hidden="true"
                  data-icon="inline-start"
                />
                Loading theme...
              </Badge>
            )}
            {isApplied && (
              <Badge variant="default" className="gap-1.5">
                <Check
                  className="size-3"
                  aria-hidden="true"
                  data-icon="inline-start"
                />
                {themeName ?? "Theme applied"}
              </Badge>
            )}
            {isError && (
              <Badge variant="destructive" className="gap-1.5">
                <AlertCircle
                  className="size-3"
                  aria-hidden="true"
                  data-icon="inline-start"
                />
                {errorMessage ?? "Error"}
              </Badge>
            )}
          </div>
        )}

        {/* Color swatches preview */}
        {isApplied && (
          <>
            <Separator />
            <div className="flex flex-col gap-2">
              <p className="text-sm font-medium text-foreground">
                Active Colors
              </p>
              <div className="grid grid-cols-4 gap-2">
                {COLOR_SWATCHES.map((swatch) => (
                  <div
                    key={swatch.variable}
                    className="flex flex-col items-center gap-1"
                  >
                    <div
                      className="size-8 rounded-md border border-border"
                      style={{
                        backgroundColor: `var(--${swatch.variable})`,
                      }}
                      aria-label={`${swatch.label} color swatch`}
                    />
                    <span className="text-[10px] leading-tight text-muted-foreground">
                      {swatch.label}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}
      </CardContent>

      <CardFooter className="flex gap-2">
        <Button
          onClick={handleApply}
          disabled={isLoading || inputValue.trim().length === 0}
          aria-busy={isLoading}
          className="gap-2"
        >
          {isLoading ? (
            <Loader2
              className="animate-spin"
              aria-hidden="true"
              data-icon="inline-start"
            />
          ) : (
            <Palette aria-hidden="true" data-icon="inline-start" />
          )}
          Apply Theme
        </Button>

        <Button
          variant="outline"
          onClick={onClear}
          disabled={isLoading || status === "idle"}
          className="gap-2"
        >
          <RotateCcw aria-hidden="true" data-icon="inline-start" />
          Reset to Default
        </Button>
      </CardFooter>
    </Card>
  )
}

"use client"

import { useCallback, useEffect, useRef, useState } from "react"
import {
  fetchThemeByOrigin,
  applyThemeModeWithAssets,
  clearTheme,
  type ThemeToken,
  type PublishedTheme,
} from "@theme-token/sdk"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Status of the theme fetching/applying lifecycle */
export type ThemeTokenStatus = "idle" | "loading" | "applied" | "error"

/** Options for the useThemeToken hook */
export interface UseThemeTokenOptions {
  /** Default origin to load on mount (overridden by localStorage if set) */
  defaultOrigin?: string
  /** localStorage key for persisting the active origin */
  storageKey?: string
  /** Callback fired after a theme is successfully applied */
  onThemeApplied?: (origin: string) => void
  /** Callback fired when the theme is cleared */
  onThemeCleared?: () => void
  /** Callback fired when an error occurs */
  onError?: (error: Error) => void
}

/** Return value of the useThemeToken hook */
export interface UseThemeTokenReturn {
  /** Currently active theme origin, or null if none */
  origin: string | null
  /** The fetched ThemeToken data, or null */
  theme: ThemeToken | null
  /** Current lifecycle status */
  status: ThemeTokenStatus
  /** Error if status is "error" */
  error: Error | null
  /** Apply a theme by origin (fetches from chain, applies CSS vars, persists) */
  setOrigin: (origin: string) => Promise<void>
  /** Clear the active theme and revert to default CSS vars */
  clearOrigin: () => void
  /** Whether a theme operation is in progress */
  isLoading: boolean
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const DEFAULT_STORAGE_KEY = "bigblocks-theme-origin"

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Manages on-chain theme loading, application, and localStorage persistence.
 *
 * Reads the saved origin from localStorage on mount, fetches the ThemeToken
 * from the blockchain via `@theme-token/sdk`, and applies its CSS variables
 * to the document root. Provides imperative methods to switch or clear themes.
 */
export function useThemeToken({
  defaultOrigin,
  storageKey = DEFAULT_STORAGE_KEY,
  onThemeApplied,
  onThemeCleared,
  onError,
}: UseThemeTokenOptions = {}): UseThemeTokenReturn {
  const [origin, setOriginState] = useState<string | null>(null)
  const [theme, setTheme] = useState<ThemeToken | null>(null)
  const [status, setStatus] = useState<ThemeTokenStatus>("idle")
  const [error, setError] = useState<Error | null>(null)

  // Stable refs for callbacks to avoid re-triggering effects
  const onThemeAppliedRef = useRef(onThemeApplied)
  onThemeAppliedRef.current = onThemeApplied
  const onThemeClearedRef = useRef(onThemeCleared)
  onThemeClearedRef.current = onThemeCleared
  const onErrorRef = useRef(onError)
  onErrorRef.current = onError

  // ------------------------------------------------------------------
  // Core: fetch + apply a theme by origin
  // ------------------------------------------------------------------

  const applyOrigin = useCallback(
    async (targetOrigin: string) => {
      setStatus("loading")
      setError(null)

      try {
        const published: PublishedTheme | null =
          await fetchThemeByOrigin(targetOrigin)

        if (!published) {
          throw new Error(
            `Theme not found for origin "${targetOrigin}". Verify the origin is a valid ThemeToken inscription.`,
          )
        }

        // Detect current color scheme
        const isDark =
          typeof document !== "undefined" &&
          document.documentElement.classList.contains("dark")
        const mode = isDark ? "dark" : "light"

        await applyThemeModeWithAssets(published.theme, mode)

        setOriginState(targetOrigin)
        setTheme(published.theme)
        setStatus("applied")

        // Persist
        if (typeof window !== "undefined") {
          localStorage.setItem(storageKey, targetOrigin)
        }

        onThemeAppliedRef.current?.(targetOrigin)
      } catch (err) {
        const e = err instanceof Error ? err : new Error(String(err))
        setError(e)
        setStatus("error")
        onErrorRef.current?.(e)
      }
    },
    [storageKey],
  )

  // ------------------------------------------------------------------
  // Public: set a new origin
  // ------------------------------------------------------------------

  const setOrigin = useCallback(
    async (newOrigin: string) => {
      await applyOrigin(newOrigin)
    },
    [applyOrigin],
  )

  // ------------------------------------------------------------------
  // Public: clear theme
  // ------------------------------------------------------------------

  const clearOrigin = useCallback(() => {
    clearTheme()
    setOriginState(null)
    setTheme(null)
    setStatus("idle")
    setError(null)

    if (typeof window !== "undefined") {
      localStorage.removeItem(storageKey)
    }

    onThemeClearedRef.current?.()
  }, [storageKey])

  // ------------------------------------------------------------------
  // Mount: restore persisted origin (or use default)
  // ------------------------------------------------------------------

  const mountedRef = useRef(false)

  useEffect(() => {
    if (mountedRef.current) return
    mountedRef.current = true

    if (typeof window === "undefined") return

    const saved = localStorage.getItem(storageKey)
    const initial = saved ?? defaultOrigin

    if (initial) {
      void applyOrigin(initial)
    }
  }, [storageKey, defaultOrigin, applyOrigin])

  return {
    origin,
    theme,
    status,
    error,
    setOrigin,
    clearOrigin,
    isLoading: status === "loading",
  }
}
